var e=[{id:`L2_1`,type:`dialog`,speaker:`RAY_SCHOOL_NPC_B`,text:{KOREA:`웃!?`,JPN:`うっ！？`,ENG:`Ugh?!`,TWN:`呃！？`},stage:{bg:`COUNTERSIDE_ASH`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RAY_SCHOOL_NPC_B`,face:`UNIT_SURPRISE`},R:null}},sfx:`FX_CUTSCEN_SWORD_HIT`},{id:`L3_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`레이 선배……? 정말 레이 선배야?`,JPN:`レイ先輩……？　本当にレイ先輩なの？`,ENG:`Ray...? Is that really you, Ray?`,TWN:`雷伊前輩……？真的是雷伊前輩嗎？`},stage:{bg:`COUNTERSIDE_ASH`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`RAY_SCHOOL_NPC_B`,text:{KOREA:`잠시만요, 여러분!`,JPN:`ちょっと待ってください、皆さん！`,ENG:`Hold on a second, everyone!`,TWN:`等等，各位！`},stage:{bg:`COUNTERSIDE_ASH`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RAY_SCHOOL_NPC_B`,face:`UNIT_SERIOUS`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`RAY_SCHOOL_NPC_B`,text:{KOREA:`진정해 주세요. 저는 마왕을 쓰러뜨리려고……`,JPN:`落ち着いて。僕は魔王を倒すために……`,ENG:`Relax, please. I am here to take down the Demon L–`,TWN:`請冷靜點，我是為了打敗魔王……`},stage:{bg:`COUNTERSIDE_ASH`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RAY_SCHOOL_NPC_B`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SEO_YOON_ALT_CA_NULL`,text:{KOREA:`뭘 멍하니 보고 있어, 유미나!`,JPN:`何ボーっとしているのよ、ミナ！`,ENG:`What are you waiting for, Yoo Mina!`,TWN:`你愣著幹什麼呢，劉米娜！`},stage:{bg:`COUNTERSIDE_ASH`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_HATE`}}}},{id:`L9_1`,type:`dialog`,speaker:`SEO_YOON_ALT_CA_NULL`,text:{KOREA:`무기까지 든 상대랑 대화로 문제가 해결될 것 같아?`,JPN:`武器を持った相手に会話でなんとかなると思う？`,ENG:`You think talking would work with someone who's got a weapon?`,TWN:`對方可是拿著武器！`},stage:{bg:`COUNTERSIDE_ASH`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`하지만……!`,JPN:`でも……！`,ENG:`But–!`,TWN:`但是……！`},stage:{bg:`COUNTERSIDE_ASH`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`SEO_YOON_ALT_CA_NULL`,text:{KOREA:`대화는 제압하고 나서 해! 네가 물렁하다는 건 잘 알고 있으니까!`,JPN:`会話は制圧してからよ！　あなたの甘い性格はよく知っているから！`,ENG:`Talk's for later! Take him down first! I know well how softhearted you are!`,TWN:`先打趴他再說！這個時候就不可以心軟！`},stage:{bg:`COUNTERSIDE_ASH`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`큭……!`,JPN:`くっ……！`,ENG:`Khhk...!`,TWN:`唔……！`},stage:{bg:`COUNTERSIDE_ASH`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};